const aiResponse = $node["Final Response"].json.response || "(Sin respuesta)";
const userMessage = $node["Init Context"].json.user_goal || "(Mensaje no detectado)";
let chatHistory = [];

try {
  // Intentar leer historial previo desde el nodo Init Context
  chatHistory = $node["Init Context"].json.chat_history || [];
} catch (e) {
  chatHistory = [];
}

// Agregar el nuevo par a la memoria
chatHistory.push({
  user: userMessage,
  ai: aiResponse,
  timestamp: new Date().toISOString()
});

// Mantener solo los últimos 15 mensajes para no saturar el contexto
const finalHistory = chatHistory.slice(-15);
const content = JSON.stringify(finalHistory, null, 2);

return [{
  json: { response: aiResponse, history: finalHistory },
  binary: {
    data: {
      data: Buffer.from(content).toString('base64'),
      mimeType: 'application/json',
      fileExtension: 'json',
      fileName: 'history.json'
    }
  }
}];

let result = "Success";
let structured_data = null;

if (items.length > 0) {
  if (items[0].json.id && items[0].json.name) {
     // Drive Search result
     result = items.map(i => `[FILE] ${i.json.name} (${i.json.id})`).join(", ");
     structured_data = items.map(i => ({ 
       id: i.json.id, 
       name: i.json.name, 
       mimeType: i.json.mimeType || 'unknown'
     }));
  } else if (items[0].json.stdout) {
     result = items[0].json.stdout;
  } else if (items[0].binary) {
     result = "Binary processed";
  }
}

// Aggregate for History WITH structured data
const prev = $('Clean Actor').last().json;
return [{ json: { 
  action_taken: prev.accion, 
  tool_result: result,
  tool_result_data: structured_data,
  planner_instruction: prev.instruction, 
  user_goal: prev.user_goal, 
  history: prev.history, 
  counter: prev.counter,
  chat_history: prev.chat_history // Pass continuous chat history
} }];

const item = $input.item.json;
const newHistory = item.history || [];

newHistory.push({
  plan: item.planner_instruction,
  action: item.action_taken,
  result: item.tool_result,
  result_data: item.tool_result_data
});

const newCounter = (item.counter || 0) + 1;

if (newCounter >= 15) {
    console.log('⚠️ Límite de iteraciones alcanzado.');
}

return [{ json: { 
  user_goal: item.user_goal, 
  history: newHistory, 
  counter: newCounter,
  chat_history: item.chat_history
} }];

// Detect user message from ANY input node
const inputs = $input.all();
let message = "";

// Check current input
if (inputs.length > 0 && inputs[0].json.chatInput) {
    message = inputs[0].json.chatInput;
} else {
    // Fallback to searching node data
    try { 
        message = $node["When chat message received"].json.chatInput; 
    } catch(e) {
        message = "No se detectó mensaje del usuario.";
    }
}

let longTermHistory = [];
try {
  const historyData = $node["Read History"].json.data || $node["Read History"].json.content;
  if (historyData) {
    longTermHistory = (typeof historyData === 'string') ? JSON.parse(historyData) : historyData;
  }
} catch (e) {
  longTermHistory = [];
}

return [{ 
  json: { 
    user_goal: message, 
    chat_history: longTermHistory, 
    history: [], 
    counter: 0 
  } 
}];

return $input.all().map(item => {
  const goal = item.json.user_goal;
  const chatHistory = item.json.chat_history || [];
  const stepHistory = item.json.history || [];

  let memoryText = chatHistory.length > 0 ? chatHistory.map(h => `Pregunta: ${h.user}\nRespuesta: ${h.ai}`).join("\n---\n") : "Esta es una nueva conversación.";
  let historyText = stepHistory.length > 0 ? stepHistory.map((h, i) => `PASO ${i+1}: ${h.action} -> ${h.result}`).join("\n") : "Aún no has ejecutado ninguna herramienta en este turno.";

  const prompt = `SISTEMA OPERATIVO VEGA. MODO: KERNEL EJECUTOR.
Usuario autenticado: Emky.

TIENES ACCESO TOTAL A LAS SIGUIENTES HERRAMIENTAS REALES:
1. buscar_en_drive(query): Devuelve IDs de archivos en Google Drive.
2. descargar_de_drive(fileId, filename): Descarga de Drive al disco local del servidor.
3. subir_a_drive(filename): Sube un archivo local a la cuenta de Drive.
4. ejecutar_comando(command): Ejecuta Bash (ls, mkdir, unzip, rm, cp, mv). MODO OBLIGATORIO para gestión de archivos locales.
5. leer_archivo(path): Lee el contenido de archivos de texto locales.

REGLAS CRÍTICAS:
- PROHIBIDO decir "No tengo acceso" o "No puedo". TIENES las herramientas arriba. ÚSALAS.
- SI EL USUARIO PIDE ALGO DE DRIVE: El primer paso SIEMPRE es buscar_en_drive(query).
- TRABAJA EN PASOS: No intentes hacer todo a la vez. Una herramienta por turno.
- FORMATO DE RESPUESTA: Solo JSON puro. No uses markdown.

OBJETIVO: "${goal}"

HISTORIAL DE CHAT:
${memoryText}

LOG TÉCNICO DE LA SESIÓN:
${historyText}

RESPUESTA JSON:
{
  "thought": "Análisis de qué herramienta necesito ahora.",
  "next_instruction": "NombreHerramienta(argumentos)",
  "is_done": false,
  "final_response": null
}`;

  return { json: { prompt, history: stepHistory, chat_history: chatHistory, user_goal: goal } };
});

const item = $input.item.json;
let raw = item.output || item.response || "";
let parsed = { is_done: false };

try {
  let text = (typeof raw === 'string') ? raw : JSON.stringify(raw);
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else if (text.trim() !== "") {
    parsed = { is_done: true, final_response: text };
  }
} catch(e) {
  parsed = { is_done: true, final_response: "Error al parsear: " + e.message };
}

// FORZAR BOOLEANOS REALES PARA N8N
parsed.is_done = (parsed.is_done === true || String(parsed.is_done).toLowerCase() === 'true');

if (parsed.is_done && (!parsed.final_response || parsed.final_response === "")) {
  parsed.final_response = "He completado la tarea solicitada.";
}

return [{ json: { ...item, planner_output: parsed } }];

const item = $input.item.json;
const instruction = item.planner_output.next_instruction;

// Pasamos también el historial de chat al actor por si acaso, aunque no es crítico
const structured_context = item.history.filter(h => h.result_data).map(h => h.result_data).flat();

const prompt = `CONVIERTE ESTO A JSON PARA HERRAMIENTAS:
Instrucción: "${instruction}"
Contexto archivos: ${JSON.stringify(structured_context)}

SALIDA: { "accion": "...", "datos": { ... } }`;

return [{ json: { ...item, prompt, instruction } }];

const item = $input.item.json;
let raw = item.final_answer || item.response || item.raw_stdout || "{}";
if (typeof raw !== 'string') raw = JSON.stringify(raw);

let parsed = {};
try { parsed = JSON.parse(raw); } catch(e) {}

let accion = (parsed.accion || parsed.action || "").toLowerCase();
const map = { 'search_drive': 'buscar_en_drive', 'download_file': 'descargar_de_drive', 'run_command': 'ejecutar_comando' };
accion = map[accion] || accion;

return [{ json: { accion, datos: parsed.datos || {}, planner_instruction: item.instruction, user_goal: item.user_goal, history: item.history, counter: item.counter, chat_history: item.chat_history } }];
